,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Add to Collection'
,p_static_id=>'add-to-collection'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_item_name VARCHAR2(100);',
'    v_price NUMBER;',
'BEGIN',
'    -- 1. Create the invisible cart if it doesn''t exist yet',
'    IF NOT APEX_COLLECTION.COLLECTION_EXISTS(''CAMPUS_CART'') THEN',
'        APEX_COLLECTION.CREATE_COLLECTION(''CAMPUS_CART'');',
'    END IF;',
'',
'    -- 2. Grab the name and price of the food they clicked',
'    SELECT item_name, price INTO v_item_name, v_price',
'    FROM menu_items WHERE item_id = :P3_ITEM_ID;',
'',
'    -- 3. Drop it into the basket',
'    APEX_COLLECTION.ADD_MEMBER(',
'        p_collection_name => ''CAMPUS_CART'',',
'        p_c001 => :P3_ITEM_ID,      -- Item ID',
'        p_c002 => :P3_VENDOR_ID,    -- Vendor ID',
'        p_c003 => v_item_name,      -- Item Name',
'        p_c004 => :P3_NOTES,        -- Notes',
'        p_n001 => v_price,          -- Unit Price',
'        p_n002 => :P3_QUANTITY      -- Quantity',
'    );',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_success_message=>'Added to Cart!'
,p_internal_uid=>152118096299425652814
);
