wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(653940587028235)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Process Checkout'
,p_static_id=>'process-checkout'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_order_id NUMBER;',
'    v_total_amount NUMBER;',
'    v_item_count NUMBER := 0;',
'    v_combined_notes VARCHAR2(4000); -- NEW: Variable to hold the stitched notes',
'BEGIN',
'    -- 1. Check if the cart has items',
'    IF APEX_COLLECTION.COLLECTION_EXISTS(''CAMPUS_CART'') THEN',
'        v_item_count := APEX_COLLECTION.COLLECTION_MEMBER_COUNT(''CAMPUS_CART'');',
'    END IF;',
'',
'    IF v_item_count > 0 THEN',
'        -- 2. Loop through each UNIQUE restaurant in the cart',
'        FOR vendor_rec IN (',
'            SELECT DISTINCT c002 AS vendor_id',
'            FROM apex_collections',
'            WHERE collection_name = ''CAMPUS_CART''',
'        ) LOOP',
'            ',
'            -- 3. Calculate total AND combine all notes for this specific vendor',
'            SELECT ',
'                SUM(n001 * n002), ',
'                LISTAGG(c004, '' | '') WITHIN GROUP (ORDER BY seq_id) ',
'            INTO v_total_amount, v_combined_notes',
'            FROM apex_collections',
'            WHERE collection_name = ''CAMPUS_CART''',
'            AND c002 = vendor_rec.vendor_id;',
'',
'            -- 4. Create the Kitchen Ticket (NOW WITH NOTES!)',
'            INSERT INTO orders (customer_id, vendor_id, order_status, total_amount, special_instructions)',
'            VALUES (1, TO_NUMBER(vendor_rec.vendor_id), ''Pending'', v_total_amount, v_combined_notes)',
'            RETURNING order_id INTO v_order_id;',
'',
'            -- 5. Attach the food items to the ticket',
'            FOR item IN (',
'                SELECT c001 AS item_id, n002 AS quantity, n001 AS unit_price',
'                FROM apex_collections',
'                WHERE collection_name = ''CAMPUS_CART''',
'                AND c002 = vendor_rec.vendor_id',
'            ) LOOP',
'                INSERT INTO order_items (order_id, item_id, quantity, unit_price)',
'                VALUES (v_order_id, TO_NUMBER(item.item_id), item.quantity, item.unit_price);',
'            END LOOP;',
'            ',
'        END LOOP;',
'',
'        -- 6. Empty the basket and save!',
